package com.abc.studentportal.postgres.entity;
import com.abc.studentportal.course.domain.CourseStatus; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="courses") public class CourseEntity { @Id private UUID id; @Column(name="code",nullable=false,unique=true) private String courseCode; @Column(nullable=false) private String title; private String description; @Column(nullable=false) private int credits; @Column(nullable=false) private int capacity; @Column(name="occupied_seats",nullable=false) private int occupiedSeats; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="department_id",nullable=false) private DepartmentEntity department; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="instructor_id",nullable=false) private InstructorEntity instructor; @Enumerated(EnumType.STRING) @Column(nullable=false) private CourseStatus status; @Column(name="created_at",nullable=false) private Instant createdAt; @Column(name="updated_at",nullable=false) private Instant updatedAt; @Version private long version; protected CourseEntity(){} public CourseEntity(UUID id,String c,String t,String d,int cr,int cap,CourseStatus s,UUID dept,UUID inst,Instant ca,Instant ua){this.id=id;courseCode=c;title=t;description=d;credits=cr;capacity=cap;status=s;department=new DepartmentEntity(dept,null,null,null,ca,ua);instructor=new InstructorEntity(inst,null,null,null,null,dept,ca,ua);createdAt=ca;updatedAt=ua;} public UUID getId(){return id;} public String getCourseCode(){return courseCode;} public String getTitle(){return title;} public String getDescription(){return description;} public int getCredits(){return credits;} public int getCapacity(){return capacity;} public CourseStatus getStatus(){return status;} public DepartmentEntity getDepartment(){return department;} public InstructorEntity getInstructor(){return instructor;} public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;} public long getVersion(){return version;} }
